    __threadfence_block();
    __syncthreads();

	for (int tid = blockIdx.x * blockDim.x + threadIdx.x; tid < size; tid += numThreads * blockIdx.y * blockIdx.z) {
		float elem = input[tid];

		int idx  = DIVISIONS/2 - 1;
		int jump = DIVISIONS/4;
