#endif
    cudaMalloc(&constStartAddr, (divisions+1)*sizeof(int));
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    err = cudaMemcpyAsync(constStartAddr, startaddr, (divisions+1)*sizeof(int), cudaMemcpyHostToDevice, mergeCommands);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to constStartAddr source array!\n");
        exit(1);
    }
#ifdef TIMING
#endif

    double mergePassTime = 0;
    int nrElems = 2;
	while(1==1){
		int floatsperthread = (nrElems*4);

		int threadsPerDiv = (int)ceil(largestSize/(float)floatsperthread);

		int threadsNeeded = threadsPerDiv * divisions;


#ifdef MERGE_WG_SIZE_1
        local.x = MERGE_WG_SIZE_1;
#else
		local.x = 208;
#endif
		int grid_x = ((threadsNeeded%local.x) == 0) ?
        threadsNeeded/local.x :
        (threadsNeeded/local.x) + 1;
		if(grid_x < 8){
			grid_x = 8;
			local.x = ((threadsNeeded%grid_x) == 0) ?
            threadsNeeded / grid_x :
            (threadsNeeded / grid_x) + 1;
		}

		float4 *tempList = d_origList;
		d_origList = d_resultList;
		d_resultList = tempList;

        cudaEventCreate(&write_event[0]);
        cudaEventCreate(&write_event[1]);
        cudaEventCreate(&read_event[0]);

        err = cudaMemcpyAsync(d_resultList_first_buff, d_resultList, listsize*sizeof(float), cudaMemcpyHostToDevice, mergeCommands);
        if (err != cudaSuccess)
        {
            printf("Error: Failed to write to d_resultList_first_buff source array!\n");
            exit(1);
        }
        cudaEventRecord(write_event[0], mergeCommands);

        err = cudaMemcpyAsync(d_origList_first_buff, d_origList, listsize*sizeof(float), cudaMemcpyHostToDevice, mergeCommands);
        if (err != cudaSuccess)
        {
            printf("Error: Failed to write to d_origList_first_buff source array!\n");
            exit(1);
        }
        cudaEventRecord(write_event[1], mergeCommands);

        dim3 global_pass(grid_x*local.x, 1, 1);

        mergeSortPass<<<global_pass, local, 0, mergeCommands>>>(d_origList_first_buff, d_resultList_first_buff, nrElems, threadsPerDiv, constStartAddr);
        if (cudaGetLastError() != cudaSuccess)
        {
            printf("Error: Failed to execute mergePass kernel!\n");
            exit(1);
        }

        cudaEventCreate(&mergePassEvent);
        cudaEventRecord(mergePassEvent, mergeCommands);
        cudaEventSynchronize(mergePassEvent);

        err = cudaMemcpyAsync(d_resultList, d_resultList_first_buff, listsize*sizeof(float), cudaMemcpyDeviceToHost, mergeCommands);
        if (err != cudaSuccess)
        {
            printf("Error: Failed to read prefix output array! %d\n", err);
            exit(1);
        }
        cudaEventRecord(read_event[0], mergeCommands);
        cudaEventSynchronize(read_event[0]);
#ifdef TIMING
#endif
        cudaEventDestroy(write_event[0]);
        cudaEventDestroy(write_event[1]);
        cudaEventDestroy(read_event[0]);

        float pass_time = 0;
        cudaEventElapsedTime(&pass_time, mergePassEvent, mergePassEvent);
        mergesum+= pass_time /1000.0;
        mergePassTime+= pass_time/1000.0;
        printf("Merge Pass Kernel Iteration Time: %0.3f \n", pass_time);
        cudaEventDestroy(mergePassEvent);
		nrElems *= 2;
		floatsperthread = (nrElems*4);

		if(threadsPerDiv == 1) break;
	}
    printf("Merge Pass Kernel Time: %0.3f \n", mergePassTime);
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    cudaMalloc(&finalStartAddr, (divisions+1)*sizeof(int));
    cudaMalloc(&nullElems, (divisions)*sizeof(int));
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    cudaEventCreate(&write_event[0]);
    cudaEventCreate(&write_event[1]);
    cudaEventCreate(&write_event[2]);
    cudaEventCreate(&write_event[3]);

    err = cudaMemcpyAsync(finalStartAddr, origOffsets, (divisions+1)*sizeof(int), cudaMemcpyHostToDevice, mergeCommands);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to finalStartAddr source array!\n");
        exit(1);
    }
    cudaEventRecord(write_event[0], mergeCommands);

    err = cudaMemcpyAsync(nullElems, nullElements, (divisions)*sizeof(int), cudaMemcpyHostToDevice, mergeCommands);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to nullElements source array!\n");
        exit(1);
    }
    cudaEventRecord(write_event[1], mergeCommands);

#ifdef MERGE_WG_SIZE_0
    local.x = MERGE_WG_SIZE_0;
#else
    local.x = 256;
#endif
	int grid_x = ((largestSize%local.x) == 0) ?
    largestSize/local.x :
    (largestSize/local.x) + 1;
	int grid_y = divisions;

    dim3 global_pack(grid_x*local.x, grid_y*1, 1);

    err = cudaMemcpyAsync(d_res, d_resultList, listsize*sizeof(float), cudaMemcpyHostToDevice, mergeCommands);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to d_resultList_first_buff source array!\n");
        exit(1);
    }
    cudaEventRecord(write_event[2], mergeCommands);

    err = cudaMemcpyAsync(d_orig, d_origList, listsize*sizeof(float), cudaMemcpyHostToDevice, mergeCommands);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to d_origList_first_buff source array!\n");
        exit(1);
    }
    cudaEventRecord(write_event[3], mergeCommands);

    mergepack<<<global_pack, local, 0, mergeCommands>>>(d_orig, d_res, constStartAddr, nullElems, finalStartAddr);
    if (cudaGetLastError() != cudaSuccess)
    {
        printf("Error: Failed to execute merge pack kernel!\n");
        exit(1);
    }

    cudaEventCreate(&mergePackEvent);
    cudaEventRecord(mergePackEvent, mergeCommands);
    cudaEventSynchronize(mergePackEvent);

#ifdef TIMING
#endif
    cudaEventDestroy(write_event[0]);
    cudaEventDestroy(write_event[1]);
    cudaEventDestroy(write_event[2]);
    cudaEventDestroy(write_event[3]);

    err = cudaMemcpyAsync(d_origList, d_orig, listsize*sizeof(float), cudaMemcpyDeviceToHost, mergeCommands);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to read origList array! %d\n", err);
        exit(1);
    }

    float pack_time = 0;
    cudaEventElapsedTime(&pack_time, mergePackEvent, mergePackEvent);
    mergesum+= pack_time / 1000.0;
    printf("Merge Pack Kernel Time: %0.3f \n", pack_time);
    cudaEventDestroy(mergePackEvent);

	free(startaddr);
	return d_origList;

}

double getMergeTime() {
  return mergesum;
}
